protocol_text:
module 00_worked_example_pr_merge;

data <java> "java.lang.String" from "rt.jar" as String;

global protocol Team0(role Author, role Merger) {
    MergeDone(String) from Merger to Author;
}

module 01_worked_example_content_pipeline;

data <java> "java.lang.String" from "rt.jar" as String;

global protocol Team1(role Editor, role Publisher, role Researcher, role Writer) {
    ResearchBrief(String) from Researcher to Writer;
    SubmitDraft(String) from Writer to Editor;
    Approve(String) from Editor to Publisher;
}

module 02_worked_example_airline_seat;

data <java> "java.lang.String" from "rt.jar" as String;

global protocol Team2(role FlightSystem, role SeatBooking, role Triage) {
    AssignFlight(String) from Triage to SeatBooking;
    UpdateSeat(String) from SeatBooking to FlightSystem;
    SeatConfirmed(String) from FlightSystem to SeatBooking;
}
